use std::io::{self, Read};
use serde::{Deserialize, Serialize};

#[derive(Deserialize, Debug)]
struct Parameters {
    #[serde(rename = "LENGTH1")] length1: f64,
    #[serde(rename = "RADIUS1")] radius1: f64,
    #[serde(rename = "EPSILON")] epsilon: f64,
    #[serde(rename = "AREA1")] area1: f64,
    #[serde(rename = "Q_PTS")] q_pts: usize,
    #[serde(rename = "QUADS")] quads: usize,
    #[serde(rename = "DIST")] dist: f64,
    #[serde(rename = "N_PTS")] n_pts: usize,
    #[serde(rename = "K_PTS")] k_pts: usize,
    #[serde(rename = "A_PTS")] a_pts: usize,
    #[serde(rename = "B_PTS")] b_pts: usize,
    #[serde(rename = "C_PTS")] c_pts: usize,
    #[serde(rename = "D_PTS")] d_pts: usize,
    #[serde(rename = "E_PTS")] e_pts: usize,
    #[serde(rename = "F_PTS")] f_pts: usize,
    #[serde(rename = "G_PTS")] g_pts: usize,
    #[serde(rename = "LENGTH2")] length2: f64,
    #[serde(rename = "RADIUS2")] radius2: f64,
    #[serde(rename = "AREA2")] area2: f64,
}

#[derive(Deserialize, Debug)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<String>>,
    pum_diag: Vec<bool>,
}

#[derive(Serialize, Debug)]
struct Output {
    cmv: Vec<bool>,
    pum: Vec<Vec<bool>>,
    fuv: Vec<bool>,
    launch: bool,
}

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

fn dist(p1: (f64, f64), p2: (f64, f64)) -> f64 {
    ((p1.0 - p2.0).powi(2) + (p1.1 - p2.1).powi(2)).sqrt()
}

fn triangle_area(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    (p1.0 * (p2.1 - p3.1) + p2.0 * (p3.1 - p1.1) + p3.0 * (p1.1 - p2.1)).abs() / 2.0
}

fn min_enclosing_circle_radius(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let mut sides = [
        dist(p1, p2),
        dist(p2, p3),
        dist(p3, p1)
    ];
    sides.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let a = sides[2];
    let b = sides[1];
    let c = sides[0];

    if realcompare(a * a, b * b + c * c) != "LT" {
        return a / 2.0;
    }

    let area = triangle_area(p1, p2, p3);
    if realcompare(area, 0.0) == "EQ" {
        return a / 2.0; 
    }

    (a * b * c) / (4.0 * area)
}

fn angle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let a1 = (p1.1 - p2.1).atan2(p1.0 - p2.0);
    let a2 = (p3.1 - p2.1).atan2(p3.0 - p2.0);
    let mut diff = (a1 - a2).abs();
    if diff > 3.1415926535 {
        diff = 2.0 * 3.1415926535 - diff;
    }
    diff
}

fn quadrant(x: f64, y: f64) -> usize {
    let x_ge_0 = realcompare(x, 0.0) == "GT" || realcompare(x, 0.0) == "EQ";
    let y_ge_0 = realcompare(y, 0.0) == "GT" || realcompare(y, 0.0) == "EQ";
    let x_lt_0 = realcompare(x, 0.0) == "LT";
    let y_lt_0 = realcompare(y, 0.0) == "LT";
    let x_le_0 = realcompare(x, 0.0) == "LT" || realcompare(x, 0.0) == "EQ";
    let x_gt_0 = realcompare(x, 0.0) == "GT";

    if x_ge_0 && y_ge_0 { return 1; }
    if x_lt_0 && y_ge_0 { return 2; }
    if x_le_0 && y_lt_0 { return 3; }
    if x_gt_0 && y_lt_0 { return 4; }
    1
}

fn dist_to_line(p0: (f64, f64), p1: (f64, f64), p2: (f64, f64)) -> f64 {
    let num = ((p2.0 - p1.0) * (p1.1 - p0.1) - (p1.0 - p0.0) * (p2.1 - p1.1)).abs();
    let den = dist(p1, p2);
    num / den
}

fn evaluate_lics(input: &Input) -> Vec<bool> {
    let mut cmv = vec![false; 15];
    let n = input.numpoints;
    let pts: Vec<(f64, f64)> = input.x.iter().zip(input.y.iter()).map(|(&x, &y)| (x, y)).collect();
    let p = &input.parameters;
    let pi = 3.1415926535;

    for i in 0..n.saturating_sub(1) {
        if realcompare(dist(pts[i], pts[i+1]), p.length1) == "GT" {
            cmv[0] = true; break;
        }
    }

    for i in 0..n.saturating_sub(2) {
        if realcompare(min_enclosing_circle_radius(pts[i], pts[i+1], pts[i+2]), p.radius1) == "GT" {
            cmv[1] = true; break;
        }
    }

    for i in 0..n.saturating_sub(2) {
        if realcompare(pts[i].0, pts[i+1].0) == "EQ" && realcompare(pts[i].1, pts[i+1].1) == "EQ" { continue; }
        if realcompare(pts[i+2].0, pts[i+1].0) == "EQ" && realcompare(pts[i+2].1, pts[i+1].1) == "EQ" { continue; }
        let ang = angle(pts[i], pts[i+1], pts[i+2]);
        if realcompare(ang, pi - p.epsilon) == "LT" || realcompare(ang, pi + p.epsilon) == "GT" {
            cmv[2] = true; break;
        }
    }

    for i in 0..n.saturating_sub(2) {
        if realcompare(triangle_area(pts[i], pts[i+1], pts[i+2]), p.area1) == "GT" {
            cmv[3] = true; break;
        }
    }

    for i in 0..n.saturating_sub(p.q_pts - 1) {
        let mut quads = vec![false; 4];
        for j in 0..p.q_pts {
            quads[quadrant(pts[i+j].0, pts[i+j].1) - 1] = true;
        }
        let count = quads.iter().filter(|&&q| q).count();
        if count > p.quads {
            cmv[4] = true; break;
        }
    }

    for i in 0..n.saturating_sub(1) {
        if realcompare(pts[i+1].0, pts[i].0) == "LT" {
            cmv[5] = true; break;
        }
    }

    if n >= 3 {
        for i in 0..n.saturating_sub(p.n_pts - 1) {
            let p_first = pts[i];
            let p_last = pts[i + p.n_pts - 1];
            let coincident = realcompare(p_first.0, p_last.0) == "EQ" && realcompare(p_first.1, p_last.1) == "EQ";
            for j in 0..p.n_pts {
                let d = if coincident {
                    dist(pts[i+j], p_first)
                } else {
                    dist_to_line(pts[i+j], p_first, p_last)
                };
                if realcompare(d, p.dist) == "GT" {
                    cmv[6] = true; break;
                }
            }
            if cmv[6] { break; }
        }
    }

    if n >= 3 {
        for i in 0..n.saturating_sub(p.k_pts + 1) {
            if realcompare(dist(pts[i], pts[i + p.k_pts + 1]), p.length1) == "GT" {
                cmv[7] = true; break;
            }
        }
    }

    if n >= 5 {
        for i in 0..n.saturating_sub(p.a_pts + p.b_pts + 2) {
            let p1 = pts[i];
            let p2 = pts[i + p.a_pts + 1];
            let p3 = pts[i + p.a_pts + p.b_pts + 2];
            if realcompare(min_enclosing_circle_radius(p1, p2, p3), p.radius1) == "GT" {
                cmv[8] = true; break;
            }
        }
    }

    if n >= 5 {
        for i in 0..n.saturating_sub(p.c_pts + p.d_pts + 2) {
            let p1 = pts[i];
            let p2 = pts[i + p.c_pts + 1];
            let p3 = pts[i + p.c_pts + p.d_pts + 2];
            if realcompare(p1.0, p2.0) == "EQ" && realcompare(p1.1, p2.1) == "EQ" { continue; }
            if realcompare(p3.0, p2.0) == "EQ" && realcompare(p3.1, p2.1) == "EQ" { continue; }
            let ang = angle(p1, p2, p3);
            if realcompare(ang, pi - p.epsilon) == "LT" || realcompare(ang, pi + p.epsilon) == "GT" {
                cmv[9] = true; break;
            }
        }
    }

    if n >= 5 {
        for i in 0..n.saturating_sub(p.e_pts + p.f_pts + 2) {
            let p1 = pts[i];
            let p2 = pts[i + p.e_pts + 1];
            let p3 = pts[i + p.e_pts + p.f_pts + 2];
            if realcompare(triangle_area(p1, p2, p3), p.area1) == "GT" {
                cmv[10] = true; break;
            }
        }
    }

    if n >= 3 {
        for i in 0..n.saturating_sub(p.g_pts + 1) {
            if realcompare(pts[i + p.g_pts + 1].0, pts[i].0) == "LT" {
                cmv[11] = true; break;
            }
        }
    }

    if n >= 3 {
        let mut c1 = false;
        let mut c2 = false;
        for i in 0..n.saturating_sub(p.k_pts + 1) {
            let d = dist(pts[i], pts[i + p.k_pts + 1]);
            if realcompare(d, p.length1) == "GT" { c1 = true; }
            if realcompare(d, p.length2) == "LT" { c2 = true; }
        }
        cmv[12] = c1 && c2;
    }

    if n >= 5 {
        let mut c1 = false;
        let mut c2 = false;
        for i in 0..n.saturating_sub(p.a_pts + p.b_pts + 2) {
            let p1 = pts[i];
            let p2 = pts[i + p.a_pts + 1];
            let p3 = pts[i + p.a_pts + p.b_pts + 2];
            let r = min_enclosing_circle_radius(p1, p2, p3);
            if realcompare(r, p.radius1) == "GT" { c1 = true; }
            if realcompare(r, p.radius2) != "GT" { c2 = true; }
        }
        cmv[13] = c1 && c2;
    }

    if n >= 5 {
        let mut c1 = false;
        let mut c2 = false;
        for i in 0..n.saturating_sub(p.e_pts + p.f_pts + 2) {
            let p1 = pts[i];
            let p2 = pts[i + p.e_pts + 1];
            let p3 = pts[i + p.e_pts + p.f_pts + 2];
            let a = triangle_area(p1, p2, p3);
            if realcompare(a, p.area1) == "GT" { c1 = true; }
            if realcompare(a, p.area2) == "LT" { c2 = true; }
        }
        cmv[14] = c1 && c2;
    }

    cmv
}

fn compute_pum(cmv: &[bool], lcm: &Vec<Vec<String>>, pum_diag: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = pum_diag[i];
                continue;
            }
            match lcm[i][j].as_str() {
                "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                "ORR" => pum[i][j] = cmv[i] || cmv[j],
                "NOTUSED" => pum[i][j] = true,
                _ => panic!("Unknown LCM value"),
            }
        }
    }
    pum
}

fn compute_fuv(pum: &Vec<Vec<bool>>, pum_diag: &[bool]) -> Vec<bool> {
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum_diag[i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if i != j && !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }
    fuv
}

fn compute_launch(fuv: &[bool]) -> bool {
    fuv.iter().all(|&v| v)
}

fn main() {
    let stdin = io::stdin();
    let mut input_data = String::new();
    stdin.lock().read_to_string(&mut input_data).expect("Failed to read stdin");

    let input: Input = serde_json::from_str(&input_data).expect("Failed to parse JSON");

    let cmv = evaluate_lics(&input);
    let pum = compute_pum(&cmv, &input.lcm, &input.pum_diag);
    let fuv = compute_fuv(&pum, &input.pum_diag);
    let launch = compute_launch(&fuv);

    let output = Output {
        cmv,
        pum,
        fuv,
        launch,
    };

    let output_json = serde_json::to_string(&output).expect("Failed to serialize output");
    println!("{}", output_json);
}
